        vector<int> arr(n);
        for (int i = 0; i < n; i++) {
            cin >> arr[i];
        }
        int m;
        cin >> m;

        if (m == 0 || n == 0 || m > n) {
            cout << 0 << endl;
            continue;
        }

        sort(arr.begin(), arr.end());

        int min_diff = INT_MAX;
        for (int i = 0; i + m - 1 < n; i++) {
