#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int cmpfunc(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int m;
        scanf("%d", &m);

        if (m == 0 || n == 0 || m > n) {
            printf("0\n");
            continue;
        }

        qsort(arr, n, sizeof(int), cmpfunc);

        int min_diff = INT_MAX;
        for (int i = 0; i + m - 1 < n; i++) {
            int diff = arr[i + m - 1] - arr[i];
            if (diff < min_diff) {
                min_diff = diff;
            }
        }
        printf("%d\n", min_diff);
    }
    return 0;
}

